<?php
declare(strict_types=1);
require_once dirname(__DIR__,2).'/includes/auth.php';require_once dirname(__DIR__,2).'/includes/conexion.php';
function falloGoogle(string $m):never{$_SESSION['mensaje_auth']=$m;header('Location: '.atenea_url('src/login/sign-in.php'));exit;}
if(($_SERVER['REQUEST_METHOD']??'')!=='POST'||!validarTokenCsrf($_POST['csrf_token']??null))falloGoogle('La solicitud de Google expiró.');
$cfg=require dirname(__DIR__,2).'/config/google.php';$autoload=dirname(__DIR__,2).'/vendor/autoload.php';if($cfg['client_id']===''||!is_file($autoload))falloGoogle('El acceso con Google aún no está configurado.');require $autoload;
try{$client=new Google_Client(['client_id'=>$cfg['client_id']]);$p=$client->verifyIdToken((string)($_POST['credential']??''));if(!$p||($p['aud']??'')!==$cfg['client_id']||empty($p['email_verified'])||empty($p['sub']))falloGoogle('No fue posible validar la cuenta de Google.');
$pdo=obtenerConexion();$q=$pdo->prepare('SELECT * FROM usuarios WHERE google_id=:gid LIMIT 1');$q->execute(['gid'=>$p['sub']]);$u=$q->fetch();if(!$u){$q=$pdo->prepare('SELECT * FROM usuarios WHERE correo=:email LIMIT 1');$q->execute(['email'=>strtolower($p['email'])]);if($q->fetch())falloGoogle('Ya existe una cuenta con este correo. Inicia sesión con tu contraseña y vincula Google desde Mi perfil.');$q=$pdo->prepare("INSERT INTO usuarios(nombre,apellido,correo,password,google_id,proveedor,email_verificado,foto,rol,estado)VALUES(:n,:a,:e,NULL,:g,'google',1,:f,'usuario','activo')");$q->execute(['n'=>substr((string)($p['given_name']??$p['name']??'Estudiante'),0,100),'a'=>substr((string)($p['family_name']??''),0,100),'e'=>strtolower($p['email']),'g'=>$p['sub'],'f'=>substr((string)($p['picture']??''),0,500)]);$q=$pdo->prepare('SELECT * FROM usuarios WHERE id=:id');$q->execute(['id'=>$pdo->lastInsertId()]);$u=$q->fetch();}if($u['estado']!=='activo')falloGoogle('La cuenta no está disponible.');iniciarSesionUsuario($u);redirigirPorRol($u['rol']);}catch(Throwable $e){error_log('Google Atenea: '.$e->getMessage());falloGoogle('No fue posible iniciar sesión con Google.');}
